package com.steelbridge.config;

import java.io.*;
import java.sql.*;
import java.util.Properties;

public class ConfigCommandExecutor {
    private static final String DB_URL = "jdbc:mysql://localhost:3306/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "apppass";

    public String run(String configPath) throws Exception {
        Properties p = new Properties();
        try (InputStream in = new FileInputStream(configPath)) {
            p.load(in);
        }
        String input = p.getProperty("q", "");

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "DELETE FROM settings WHERE config_key = '" + input + "'";
            try (Statement st = conn.createStatement()) {
                boolean ok = st.execute(sql);
                return ok ? "ok" : "no_result";
            }
        }
    }
}

